    int longestSubsequence(string s, int k) {
        int n = s.length();
        int dp[n+1];

        for (int i = 1; i <= n; i++) {
            dp[i] = 1;
        }

        for (int i = 1; i <= n; i++) {
            if (s[i-1] == '1') {
                dp[i] = 2*dp[i-1] + dp[i-2];
            }
        }

        return dp[n];
